resource "aws_s3_bucket_policy" "{bucket}_ssl" {
  bucket = "{bucket}"
  policy = jsonencode({
    Statement = [{
      Effect = "Deny"
      Principal = "*"
      Action = "s3:*"
      Resource = "arn:aws:s3:::{bucket}/*"
      Condition = {
        Bool = { "aws:SecureTransport" = "false" }
      }
    }]
  })
}

resource "aws_cloudtrail" "main" {
  name = "main-trail"
  s3_bucket_name = aws_s3_bucket.cloudtrail.id
  is_multi_region_trail = true
  enable_logging = true
}
